const text = $input.item.json.response || '';
const cleaned = text.replace(/```json\n?/g, '').replace(/```/g, '').trim();
const parsed = JSON.parse(cleaned);
return [{ json: {
  name: parsed.name,
  description: parsed.description,
  good_for: parsed.good_for,
  userMessage: $('Parse Router').first().json.userMessage,
  chatId: $('Parse Router').first().json.chatId
}}];

const response = String($('Execute New Agent').first().json.response || '');
const userMessage = $('Parse New Agent').first().json.userMessage;
let score = 7;
if (response.length > 80) score += 1;
if (response.length > 300) score += 1;
if (response.length < 30) score -= 2;
score = Math.max(1, Math.min(10, score));
return [{ json: {
  score,
  deductions: score >= 8 ? 'נראה טוב בבדיקה מהירה' : 'תשובה קצרה או חלקית בבדיקה מהירה',
  improvement: 'אפשר להריץ הערכה עמוקה ידנית אם צריך',
  agentName: $('Parse New Agent').first().json.name,
  chatId: $('Parse New Agent').first().json.chatId,
  userMessage
}}];

const input = $input.item.json || {};
if (input.score) {
  return [{ json: {
    score: input.score || 7,
    deductions: input.deductions || '',
    improvement: input.improvement || '',
    agentName: input.agentName || $('Parse New Agent').first().json.name,
    chatId: input.chatId || $('Parse New Agent').first().json.chatId
  }}];
}

const text = input.response || '';
const cleaned = text.replace(/```json\n?/g, '').replace(/```/g, '').trim();
let parsed;
try {
  parsed = JSON.parse(cleaned);
} catch(e) {
  parsed = { score: 5, deductions: 'לא ניתן להעריך', improvement: '' };
}
return [{ json: {
  score: parsed.score || 5,
  deductions: parsed.deductions || '',
  improvement: parsed.improvement || '',
  agentName: $('Parse New Agent').first().json.name,
  chatId: $('Parse New Agent').first().json.chatId
}}];

